import json, sys, re, os

TRANSCRIPT_DIRS = [
 'docs/p3-wave1-reports/transcripts',
 'docs/p3-wave2-reports',
]
BASE='/Users/amanigga/Desktop/TAMAZIA-REBUILD/tamazia-audit-engine'

# signals in assistant text that indicate a correction / false start / discovered bug
CORR = re.compile(r'\b(wait|actually|oops|whoops|that\'?s wrong|i was wrong|mistake|false start|let me fix|the bug|the real bug|turns out|it turns out|silently|masquerad|off by one|off-by-one|regression|the test fail|tests fail|failing test|broke|broken|re-?ran|re-?run|stale|race|hang|hung|timeout|timed out|ReferenceError|TypeError|TDZ|ReDoS|quarantin|escape|escaped|leak|leaked|contradiction|mismatch|shape bug|wrong shape|dead code|orphan|never called|never ran|fail open|fail-open|fail closed|swallow|corrupt|wrong assumption|i assumed|incorrectly|double-count|drift|drifted|no-op|no op)\b', re.I)

def text_of(content):
    if isinstance(content,str): return content
    out=[]
    if isinstance(content,list):
        for b in content:
            if isinstance(b,dict):
                if b.get('type')=='text': out.append(b.get('text',''))
    return '\n'.join(out)

def tool_results(content):
    out=[]
    if isinstance(content,list):
        for b in content:
            if isinstance(b,dict) and b.get('type')=='tool_result':
                c=b.get('content')
                txt=''
                if isinstance(c,str): txt=c
                elif isinstance(c,list):
                    for x in c:
                        if isinstance(x,dict) and x.get('type')=='text': txt+=x.get('text','')
                out.append((b.get('is_error',False),txt))
    return out

for d in TRANSCRIPT_DIRS:
    dd=os.path.join(BASE,d)
    for fn in sorted(os.listdir(dd)):
        if not fn.endswith('.jsonl'): continue
        path=os.path.join(dd,fn)
        corr_hits=[]
        err_hits=[]
        with open(path) as fh:
            for line in fh:
                try: o=json.loads(line)
                except: continue
                t=o.get('type')
                msg=o.get('message',{})
                content=msg.get('content') if isinstance(msg,dict) else None
                if t=='assistant' and content is not None:
                    txt=text_of(content)
                    for m in CORR.finditer(txt):
                        s=max(0,m.start()-120); e=min(len(txt),m.end()+180)
                        snip=txt[s:e].replace('\n',' ')
                        corr_hits.append(snip)
                if t in ('user','attachment') and content is not None:
                    for is_err,txt in tool_results(content):
                        if is_err or re.search(r'\b(FAIL|Error|error:|not ok|✗|failed|Exception|cannot|ENOSPC|ENOENT|127|Traceback)\b',txt):
                            snip=txt[:400].replace('\n',' ')
                            err_hits.append(('ERR' if is_err else 'txt',snip))
        print('\n\n########## FILE:',fn,'##########')
        print('--- CORRECTION SIGNALS (%d) ---'%len(corr_hits))
        seen=set()
        for h in corr_hits:
            k=h.strip()[:80]
            if k in seen: continue
            seen.add(k)
            print('  •',h.strip())
        print('--- TOOL ERROR SIGNALS (%d) ---'%len(err_hits))
        seen=set()
        for tag,h in err_hits:
            k=h.strip()[:90]
            if k in seen: continue
            seen.add(k)
            print('  [%s]'%tag,h.strip()[:300])
PYEOF
